+    let resolved = match candidate.canonicalize() {
+        Ok(resolved) => resolved,
+        Err(e) if e.kind() == std::io::ErrorKind::NotFound => {
+            return Err(StorageError::InvalidPath(format!(
+                "Attachment not found: {}",
